import subprocess, os
ref='ufrmtgriqpyzqaewvtgn'
hosts=['aws-0-ap-south-1.pooler.supabase.com']
ports=['5432','6543']
users=[f'postgres.{ref}','postgres']
for host in hosts:
  for port in ports:
    for user in users:
      dsn=f"postgresql://{user}:{os.environ.get('SUPABASE_DB_PASSWORD','')}@{host}:{port}/postgres?sslmode=require&connect_timeout=4"
      p=subprocess.run(['/opt/homebrew/opt/libpq/bin/psql', dsn, '-c', 'select 1;'], capture_output=True, text=True)
      out=(p.stderr or '') + (p.stdout or '')
      if 'Tenant or user not found' in out:
        status='tenant_or_user_not_found'
      elif 'password authentication failed' in out:
        status='password_auth_failed'
      elif 'database "postgres" does not exist' in out:
        status='db_not_found'
      elif p.returncode==0:
        status='connected'
      else:
        status='other_error'
      print(f'{host}:{port} user={user} => {status}')
PY
